//Reaction R11 (Node 16) --| R9 (JNK1)
const double k_R11_R9 = 3.5E-6;

//Reaction R7 (Inh IL-1B sig) --| R6 (IL-1B signaling)
const double k_R7_R6 = 1.7999999999999998E-4;

//Reaction R5 (IL-1B R I) --| R4 (IL-1B R I)
const double k_R5_R4 = 0.024;

//Reaction R6 (IL-1B signaling) --> R0 (ERK)
const double k_R6_R0 = 6.0E-5;

//Reaction R2 (FZD I) --| R1 (FZD)
const double k_R2_R1 = 0.024;

//Reaction R10 (Node 15) --| R15 (p38)
const double k_R10_R15 = 5.0E-6;

//Reaction R6 (IL-1B signaling) --> R15 (p38)
const double k_R6_R15 = 1.0E-4;

//Reaction R4 (IL-1B R I) --| R14 (Wnt signalir)
const double k_R4_R14 = 0.009000000000000001;

//Reaction R14 (Wnt signalir) --> R0 (ERK)
const double k_R14_R0 = 2.2000000000000003E-5;

//Reaction R13 (Wnt) --> R1 (FZD)
const double k_R13_R1 = 0.009000000000000001;

//Reaction R8 (Inh Wnt sig) --| R14 (Wnt signalir)
const double k_R8_R14 = 2.8000000000000003E-4;

//Reaction R12 (Node 17) --| R0 (ERK)
const double k_R12_R0 = 3.5E-6;

//Reaction R1 (FZD) --> R14 (Wnt signalir)
const double k_R1_R14 = 0.036;

//Reaction R4 (IL-1B R I) --> R5 (IL-1B R I)
const double k_R4_R5 = 0.002;

//Reaction R3 (IL-1B) --> R4 (IL-1B R I)
const double k_R3_R4 = 4.0E-5;

//Reaction R4 (IL-1B R I) --> R6 (IL-1B signaling)
const double k_R4_R6 = 0.036;

//Reaction R1 (FZD) --| R6 (IL-1B signaling)
const double k_R1_R6 = 0.005;

//Reaction R6 (IL-1B signaling) --> R9 (JNK1)
const double k_R6_R9 = 8.999999999999999E-5;

template.declaration:
double rateR0() {
	double R6_R0_r = k_R6_R0 * (R0Levels - R0) * R6;
	double R14_R0_r = k_R14_R0 * (R0Levels - R0) * R14;
	double R12_R0_r = k_R12_R0 * R0 * R12;
	return R6_R0_r + R14_R0_r - R12_R0_r;
}

double boundedRateR0() {
	double r = rateR0();
	if (R0 + r > R0Levels) {
		return R0Levels - R0;
	} else if (R0 + r < 0) {
		return -R0;
	}
	return r;
}

double rateR1() {
	double R2_R1_r = k_R2_R1 * R2;
	double R13_R1_r = k_R13_R1 * (R1Levels - R1) * R13;
	return  - R2_R1_r + R13_R1_r;
}

double boundedRateR1() {
	double r = rateR1();
	if (R1 + r > R1Levels) {
		return R1Levels - R1;
	} else if (R1 + r < 0) {
		return -R1;
	}
	return r;
}

double rateR2() {
	return 0;
}

double boundedRateR2() {
	return 0;
}

double rateR3() {
	return 0;
}

double boundedRateR3() {
	return 0;
}

double rateR4() {
	double R5_R4_r = k_R5_R4 * R5;
	double R3_R4_r = k_R3_R4 * (R4Levels - R4) * R3;
	return  - R5_R4_r + R3_R4_r;
}

double boundedRateR4() {
	double r = rateR4();
	if (R4 + r > R4Levels) {
		return R4Levels - R4;
	} else if (R4 + r < 0) {
		return -R4;
	}
	return r;
}

double rateR5() {
	double R4_R5_r = k_R4_R5 * R4;
	return R4_R5_r;
}

double boundedRateR5() {
	double r = rateR5();
	if (R5 + r > R5Levels) {
		return R5Levels - R5;
	} else if (R5 + r < 0) {
		return -R5;
	}
	return r;
}

double rateR6() {
	double R7_R6_r = k_R7_R6 * R6 * R7;
	double R4_R6_r = k_R4_R6 * R4;
	double R1_R6_r = k_R1_R6 * R6 * R1;
	return  - R7_R6_r + R4_R6_r - R1_R6_r;
}

double boundedRateR6() {
	double r = rateR6();
	if (R6 + r > R6Levels) {
		return R6Levels - R6;
	} else if (R6 + r < 0) {
		return -R6;
	}
	return r;
}

