	double R8_R14_r = k_R8_R14 * R14 * R8;
	double R1_R14_r = k_R1_R14 * R1;
	return  - R4_R14_r - R8_R14_r + R1_R14_r;
}

double boundedRateR14() {
	double r = rateR14();
	if (R14 + r > R14Levels) {
